import{_ as a,o,c as t,a0 as s}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"ADR-0010: ADR-010: Hierarquia de Levels de Abstração e o Papel do Tempo","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0010-abstraction-levels-and-time.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0010-abstraction-levels-and-time.md","lastUpdated":1782593311000}'),r={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0010-abstraction-levels-and-time.md"};function i(d,e,n,l,c,p){return o(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="adr-0010-adr-010-hierarquia-de-levels-de-abstracao-e-o-papel-do-tempo" tabindex="-1">ADR-0010: ADR-010: Hierarquia de Levels de Abstração e o Papel do Tempo <a class="header-anchor" href="#adr-0010-adr-010-hierarquia-de-levels-de-abstracao-e-o-papel-do-tempo" aria-label="Permalink to &quot;ADR-0010: ADR-010: Hierarquia de Levels de Abstração e o Papel do Tempo&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted</p><h2 id="context-detailed-analysis" tabindex="-1">Context / Detailed Analysis <a class="header-anchor" href="#context-detailed-analysis" aria-label="Permalink to &quot;Context / Detailed Analysis&quot;">​</a></h2><p><strong>Contexto:</strong> Discussão sobre qualidade do L3 atual e o que os levels acima de L2 deveriam ser.</p><hr><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O pipeline NEXUS opera sobre quatro layers de abstração (L0–L3). A qualidade do L3 atual demonstrou-se insuficiente: insights gerados pelo <code>qwen2.5-coder:1.5b</code> por chunk individual são superficiais porque o contexto de entrada (~200 chars) é pequeno demais para derivar invariantes arquiteturais reais.</p><p>Esta decisão formaliza a semântica de cada level e estabelece como o <strong>tempo</strong> se encaixa no modelo.</p><hr><h2 id="hierarquia-de-levels" tabindex="-1">Hierarquia de Levels <a class="header-anchor" href="#hierarquia-de-levels" aria-label="Permalink to &quot;Hierarquia de Levels&quot;">​</a></h2><p>Cada level responde uma pergunta que o anterior não consegue responder sozinho.</p><table tabindex="0"><thead><tr><th>Level</th><th>Pergunta</th><th>Granularidade</th><th>Modelo</th></tr></thead><tbody><tr><td>L0</td><td>O que está escrito?</td><td>chunk (~2000 chars)</td><td>— (verbatim)</td></tr><tr><td>L1</td><td>O que existe?</td><td>blob (arquivo completo)</td><td>ast-grep (determinístico)</td></tr><tr><td>L2</td><td>O que faz?</td><td>chunk → semântico</td><td>Gemini Flash</td></tr><tr><td>L3</td><td>O que significa?</td><td>blob → propósito</td><td>Mistral local</td></tr><tr><td>L4</td><td>O que emerge?</td><td>cluster de blobs → padrões</td><td>Gemini Flash / Sonnet</td></tr><tr><td>L5</td><td>O que pode estar errado?</td><td>sistema → hipóteses falsificáveis</td><td>Sonnet</td></tr><tr><td>L6</td><td>O que o sistema quer ser?</td><td>projeto → modelo mental</td><td>Opus / thinking models</td></tr></tbody></table><p><strong>Regra fundamental:</strong> a abstração só pode ser tão boa quanto o contexto que ela recebe. L3 alimentado por um chunk produz ruído. L3 alimentado pelos L2s de um blob inteiro produz síntese útil.</p><hr><h2 id="o-papel-do-tempo" tabindex="-1">O Papel do Tempo <a class="header-anchor" href="#o-papel-do-tempo" aria-label="Permalink to &quot;O Papel do Tempo&quot;">​</a></h2><p>O tempo no NEXUS não é uma dimensão única — são três mecanismos complementares:</p><h3 id="_1-tempo-como-evolucao-ja-existe-em-t2" tabindex="-1">1. Tempo como evolução (já existe em T2) <a class="header-anchor" href="#_1-tempo-como-evolucao-ja-existe-em-t2" aria-label="Permalink to &quot;1. Tempo como evolução (já existe em T2)&quot;">​</a></h3><p><code>blobs.prev_blob_id</code> + <code>blobs.is_current</code> + link <code>EVOLVED_FROM</code> no <code>hilbert_bridge</code>. Captura a história de como o código mudou. Permite queries do tipo &quot;qual era o propósito deste módulo 3 meses atrás?&quot;.</p><h3 id="_2-tempo-como-decay-a-implementar" tabindex="-1">2. Tempo como decay (a implementar) <a class="header-anchor" href="#_2-tempo-como-decay-a-implementar" aria-label="Permalink to &quot;2. Tempo como decay (a implementar)&quot;">​</a></h3><p><code>abstractions.last_accessed_at</code> + <code>abstractions.access_count</code> existem no schema mas não são usados. A ideia: abstrações não acessadas há muito tempo perdem peso nas buscas — memória que desvanece naturalmente, como em sistemas cognitivos reais. Isso evita que insights obsoletos contaminem queries sobre o estado atual.</p><h3 id="_3-tempo-como-dimensao-algebrica-visao-futura-—-ver-adr-011" tabindex="-1">3. Tempo como dimensão algébrica (visão futura — ver ADR-011) <a class="header-anchor" href="#_3-tempo-como-dimensao-algebrica-visao-futura-—-ver-adr-011" aria-label="Permalink to &quot;3. Tempo como dimensão algébrica (visão futura — ver ADR-011)&quot;">​</a></h3><p>Em T5, o tempo seria uma dimensão do espaço de conceitos — permitindo &quot;fatiar&quot; o sistema em qualquer instante passado e comparar topologias. Isso requer T5 implementado.</p><hr><h2 id="decisao" tabindex="-1">Decisão <a class="header-anchor" href="#decisao" aria-label="Permalink to &quot;Decisão&quot;">​</a></h2><ol><li><p><strong>L3 será reformulado</strong> para operar por blob (agrupando todos os L2s do mesmo blob), não por chunk individual. Modelo: Mistral local (já disponível na GTX).</p></li><li><p><strong>L4 será experimental</strong> — síntese cross-blob sobre clusters relacionados por similaridade vetorial ou links topológicos. Modelo: Gemini Flash.</p></li><li><p><strong>L5/L6 são visão</strong> — não implementar agora, registrar a semântica.</p></li><li><p><strong>Decay será ativado</strong> como mecanismo de ponderação nas queries T3, usando <code>last_accessed_at</code>. Abstrações acessadas recentemente ganham boost; antigas, penalidade.</p></li><li><p><strong>Evolução temporal (prev_blob_id)</strong> permanece como está — fundação sólida.</p></li></ol><hr><h2 id="adendo-pipeline-de-dois-estagios-para-l3-mistral-como-provocador" tabindex="-1">Adendo: Pipeline de Dois Estágios para L3 (Mistral como Provocador) <a class="header-anchor" href="#adendo-pipeline-de-dois-estagios-para-l3-mistral-como-provocador" aria-label="Permalink to &quot;Adendo: Pipeline de Dois Estágios para L3 (Mistral como Provocador)&quot;">​</a></h2><p>A qualidade do L3 depende não só do contexto (L2s por blob) mas da <strong>qualidade do prompt</strong> entregue ao modelo externo (Sonnet/Gemini). Um prompt genérico produz insights genéricos.</p><h3 id="arquitetura-proposta" tabindex="-1">Arquitetura proposta <a class="header-anchor" href="#arquitetura-proposta" aria-label="Permalink to &quot;Arquitetura proposta&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L2s do blob</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>  Mistral local  ← semente rotacionada</span></span>
<span class="line"><span>  &quot;dado esses resumos, [papel] + [foco] + [tom]&quot;</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>  prompt enriquecido + hipóteses especulativas</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>  Sonnet / Gemini Flash</span></span>
<span class="line"><span>  &quot;aqui o contexto + as hipóteses. valide, refute, derive invariantes.&quot;</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>  L3 de alta qualidade</span></span></code></pre></div><p>O Mistral não precisa ter razão — precisa fazer as <strong>perguntas certas</strong> para provocar o modelo externo a raciocinar mais fundo do que faria com um prompt genérico.</p><h3 id="rotacao-de-sementes" tabindex="-1">Rotação de sementes <a class="header-anchor" href="#rotacao-de-sementes" aria-label="Permalink to &quot;Rotação de sementes&quot;">​</a></h3><p>Cada execução do L3 sorteia uma combinação de três dimensões:</p><p><strong>Papel do Mistral</strong> (quem ele está sendo):</p><ul><li>Cético — &quot;o que pode estar errado aqui?&quot;</li><li>Arqueólogo — &quot;o que este código revela sobre decisões passadas?&quot;</li><li>Usuário externo — &quot;o que alguém novo precisaria saber sobre este módulo?&quot;</li><li>Detetive — &quot;o que está oculto mas presente?&quot;</li><li>Físico — &quot;quais são as forças e tensões em jogo?&quot;</li></ul><p><strong>Foco</strong> (o que observar):</p><ul><li>Contratos externos — o que este módulo promete ao resto do sistema</li><li>Invariantes internos — o que nunca pode mudar sem quebrar tudo</li><li>Acoplamentos implícitos — o que depende de quê sem declarar</li><li>Evolução provável — para onde este código parece estar indo</li></ul><p><strong>Tom</strong> (como formular):</p><ul><li>Afirmativo — &quot;este módulo é responsável por...&quot;</li><li>Interrogativo — &quot;por que este módulo precisa de...?&quot;</li><li>Hipotético — &quot;se X mudar, o que quebra?&quot;</li></ul><h3 id="por-que-rotacionar" tabindex="-1">Por que rotacionar <a class="header-anchor" href="#por-que-rotacionar" aria-label="Permalink to &quot;Por que rotacionar&quot;">​</a></h3><p>Um mesmo blob executado N vezes com sementes diferentes acumula L3s com perspectivas genuinamente distintas. O L4 futuro sintetiza esses L3s divergentes numa visão mais completa do que qualquer execução única produziria — análogo a como ensemble methods em ML superam modelos individuais ao explorar o espaço de hipóteses de forma diversa.</p><p>Sem rotação, o L3 converge para um padrão fixo determinado pelo prompt — viés sistemático que se propaga para L4 e L5.</p><hr><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><ul><li><code>run_reflect</code> no Rust precisa ser reescrito para agregar L2s por blob antes de gerar L3.</li><li>O pipeline L3 passa a ter dois estágios: Mistral local (provocador) → modelo externo (síntese).</li><li>A semente (papel × foco × tom) é sorteada por execução e salva em <code>reflections.metadata</code> para rastreabilidade.</li><li>O mesmo blob pode ter múltiplos L3s com perspectivas diferentes — schema deve permitir <code>(blob_id, seed_hash)</code> como chave, não apenas <code>blob_id</code>.</li><li><code>last_accessed_at</code> deve ser atualizado toda vez que uma abstração for retornada por <code>nexus_query</code>.</li><li>L4+ ficam documentados mas não implementados até validação do L3 reformulado.</li></ul><hr><h2 id="adendo-batch-size-e-teste-a-b-ollama-vs-antigravity-na-ingestao-l2" tabindex="-1">Adendo: Batch Size e Teste A/B Ollama vs Antigravity na Ingestão L2 <a class="header-anchor" href="#adendo-batch-size-e-teste-a-b-ollama-vs-antigravity-na-ingestao-l2" aria-label="Permalink to &quot;Adendo: Batch Size e Teste A/B Ollama vs Antigravity na Ingestão L2&quot;">​</a></h2><p>O engine Rust processa L2 em batches de 50 abstractions por ciclo (<code>LIMIT 50</code>). Durante reindexações completas (ex: intraclinica-ng com potencial de 50k+ chunks), isso representa um gargalo significativo na GPU local (GTX 1660 Super, 6GB VRAM).</p><h3 id="opcoes-de-backend-para-l2" tabindex="-1">Opções de backend para L2 <a class="header-anchor" href="#opcoes-de-backend-para-l2" aria-label="Permalink to &quot;Opções de backend para L2&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Backend</th><th>Batch size ideal</th><th>Latência por chunk</th><th>Custo</th><th>Quando usar</th></tr></thead><tbody><tr><td><code>qwen2.5-coder:1.5b</code> (Ollama local)</td><td>50</td><td>~200ms</td><td>zero</td><td>desenvolvimento, testes, chunks sensíveis</td></tr><tr><td>Antigravity proxy (Gemini Flash)</td><td>200–500</td><td>~80ms</td><td>quota API</td><td>ingestão de projetos grandes</td></tr></tbody></table><h3 id="teste-a-b-proposto" tabindex="-1">Teste A/B proposto <a class="header-anchor" href="#teste-a-b-proposto" aria-label="Permalink to &quot;Teste A/B proposto&quot;">​</a></h3><p>Durante a ingestão do intraclinica-ng, comparar:</p><ul><li><strong>Ramo A</strong>: Ollama local, batch=50, sem paralelismo externo</li><li><strong>Ramo B</strong>: Antigravity proxy, batch=200–500, paralelismo controlado pelo pool de contas</li></ul><p>Métricas a comparar: tempo total de ingestão, qualidade dos L2s (amostra manual de 20 chunks), taxa de erros, consumo de quota.</p><h3 id="implicacoes-de-implementacao" tabindex="-1">Implicações de implementação <a class="header-anchor" href="#implicacoes-de-implementacao" aria-label="Permalink to &quot;Implicações de implementação&quot;">​</a></h3><ul><li>O batch size deve ser configurável via env var <code>ENRICHMENT_BATCH_SIZE</code> (padrão: 50)</li><li>O <code>ENRICHMENT_MODEL</code> env já diferencia o backend; batch size maior só faz sentido com Antigravity</li><li>O proxy Antigravity já implementa retry exponencial e pool de contas — adequado para batches maiores</li><li>Resultado do teste A/B deve atualizar este ADR com o batch size canônico por backend</li></ul><hr><h2 id="adendo-fronteira-fractal-—-l3-contextualizado-por-vizinhos-topologicos" tabindex="-1">Adendo: Fronteira Fractal — L3 Contextualizado por Vizinhos Topológicos <a class="header-anchor" href="#adendo-fronteira-fractal-—-l3-contextualizado-por-vizinhos-topologicos" aria-label="Permalink to &quot;Adendo: Fronteira Fractal — L3 Contextualizado por Vizinhos Topológicos&quot;">​</a></h2><h3 id="ideia" tabindex="-1">Ideia <a class="header-anchor" href="#ideia" aria-label="Permalink to &quot;Ideia&quot;">​</a></h3><p>O pipeline L3 atual recebe apenas os L2s do blob atual para gerar o insight. A hipótese fractal propõe que o modelo de L3 receba também <strong>fragmentos dos L3s dos blobs topologicamente vizinhos</strong> (via <code>hilbert_bridge</code> ou links de supersession), expandindo o contexto como uma fronteira fractal — não linearmente, mas explorando as arestas do grafo de conhecimento já existente.</p><h3 id="propriedade-autorreferente" tabindex="-1">Propriedade autorreferente <a class="header-anchor" href="#propriedade-autorreferente" aria-label="Permalink to &quot;Propriedade autorreferente&quot;">​</a></h3><p>O modelo usa conhecimento interno (L2s + L3s já gerados) para gerar hipóteses sobre um novo blob, e essas hipóteses alimentam futuros L3s que se tornam contexto para próximas execuções. A fronteira cresce usando apenas o que o sistema já sabe — sem dados externos.</p><p>É análogo a como um fractal gera complexidade a partir de uma regra simples aplicada recursivamente sobre seu próprio output: <code>L3(blob_n) = f(L2s(blob_n) + L3s(vizinhos(blob_n)))</code>.</p><h3 id="o-que-isso-resolve" tabindex="-1">O que isso resolve <a class="header-anchor" href="#o-que-isso-resolve" aria-label="Permalink to &quot;O que isso resolve&quot;">​</a></h3><p>O L3 atual é &quot;cego&quot; ao grafo — gera insights isolados por blob. Com vizinhança topológica, o L3 de um guard Angular passaria a receber o L3 do serviço que ele protege e do módulo que o declara, produzindo insights que atravessam camadas arquiteturais.</p><h3 id="estado-atual" tabindex="-1">Estado atual <a class="header-anchor" href="#estado-atual" aria-label="Permalink to &quot;Estado atual&quot;">​</a></h3><p><strong>Não implementado.</strong> O <code>hilbert_bridge</code> não está populado no pipeline v5 atual. A implementação requer:</p><ol><li>Popular <code>hilbert_bridge</code> com arestas de co-ocorrência/import entre blobs</li><li>No ciclo L3, fazer JOIN <code>hilbert_bridge</code> para recuperar L3s dos N vizinhos mais próximos</li><li>Injetar fragmentos dos L3s vizinhos no prompt do modelo de reflexão antes do L2 atual</li></ol><h3 id="proximos-passos" tabindex="-1">Próximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos passos&quot;">​</a></h3><ul><li>Avaliar se <code>hilbert_bridge</code> deve ser populado pelo engine Rust (watcher de imports) ou offline (análise de grafo)</li><li>Definir N (número de vizinhos) e estratégia de truncamento para caber na janela de contexto</li><li>Registrar resultado em ADR dedicado quando implementado</li></ul>`,71)])])}const h=a(r,[["render",i]]);export{m as __pageData,h as default};
